{
  "sentences": [
    {
      "text": "我從早上八點工作到下午五點。",
      "pinyin": "Wǒ cóng zǎoshang bā diǎn gōngzuò dào xiàwǔ wǔ diǎn.",
      "pinyin_numeric": "wo3 cong2 zao3shang4 ba1 dian3 gong1zuo4 dao4 xia4wu3 wu3 dian3.",
      "translation_en": "I work from 8 AM to 5 PM.",
      "translation_ko": "저는 아침 8시부터 오후 5시까지 일해요."
    },
    {
      "text": "他從台北坐火車到高雄。",
      "pinyin": "Tā cóng Táiběi zuò huǒchē dào Gāoxióng.",
      "pinyin_numeric": "ta1 cong2 Tai2bei3 zuo4 huo3che1 dao4 Gao1xiong2.",
      "translation_en": "He takes the train from Taipei to Kaohsiung.",
      "translation_ko": "그는 타이베이에서 가오슝까지 기차를 타요."
    },
    {
      "text": "我們從昨天到今天都在準備考試。",
      "pinyin": "Wǒmen cóng zuótiān dào jīntiān dōu zài zhǔnbèi kǎoshì.",
      "pinyin_numeric": "wo3men5 cong2 zuo2tian1 dao4 jin1tian1 dou1 zai4 zhun3bei4 kao3shi4.",
      "translation_en": "We have been preparing for the exam from yesterday to today.",
      "translation_ko": "우리는 어제부터 오늘까지 시험 준비를 하고 있어요."
    },
    {
      "text": "這家餐廳從中午十二點營業到晚上十點。",
      "pinyin": "Zhè jiā cāntīng cóng zhōngwǔ shí'èr diǎn yíngyè dào wǎnshàng shí diǎn.",
      "pinyin_numeric": "zhe4 jia1 can1ting1 cong2 zhong1wu3 shi2'er4 dian3 ying2ye4 dao4 wan3shang4 shi2 dian3.",
      "translation_en": "This restaurant is open from 12 PM to 10 PM.",
      "translation_ko": "이 식당은 낮 12시부터 밤 10시까지 영업해요."
    },
    {
      "text": "我從公司走路到捷運站。",
      "pinyin": "Wǒ cóng gōngsī zǒulù dào jiéyùn zhàn.",
      "pinyin_numeric": "wo3 cong2 gong1si1 zou3lu4 dao4 jie2yun4 zhan4.",
      "translation_en": "I walk from the company to the MRT station.",
      "translation_ko": "저는 회사에서 지하철역까지 걸어가요."
    },
    {
      "text": "她從星期一學中文學到星期五。",
      "pinyin": "Tā cóng xīngqī yī xué zhōngwén xué dào xīngqī wǔ.",
      "pinyin_numeric": "ta1 cong2 xing1qi1 yi1 xue2 zhong1wen2 xue2 dao4 xing1qi1 wu3.",
      "translation_en": "She studies Chinese from Monday to Friday.",
      "translation_ko": "그녀는 월요일부터 금요일까지 중국어를 배워요."
    },
    {
      "text": "我們從公園走到圖書館。",
      "pinyin": "Wǒmen cóng gōngyuán zǒu dào túshūguǎn.",
      "pinyin_numeric": "wo3men5 cong2 gong1yuan2 zou3 dao4 tu2shu1guan3.",
      "translation_en": "We walk from the park to the library.",
      "translation_ko": "우리는 공원에서 도서관까지 걸어요."
    },
    {
      "text": "他從早上六點起床到現在都沒休息。",
      "pinyin": "Tā cóng zǎoshang liù diǎn qǐchuáng dào xiànzài dōu méi xiūxi.",
      "pinyin_numeric": "ta1 cong2 zao3shang4 liu4 dian3 qi3chuang2 dao4 xian4zai4 dou1 mei2 xiu1xi5.",
      "translation_en": "He hasn't rested from getting up at 6 AM until now.",
      "translation_ko": "그는 아침 6시에 일어난 후부터 지금까지 쉬지 않았어요."
    },
    {
      "text": "我從家裡帶咖啡到辦公室。",
      "pinyin": "Wǒ cóng jiā lǐ dài kāfēi dào bàngōngshì.",
      "pinyin_numeric": "wo3 cong2 jia1 li3 dai4 ka1fei1 dao4 ban4gong1shi4.",
      "translation_en": "I bring coffee from home to the office.",
      "translation_ko": "저는 집에서 사무실까지 커피를 가져와요."
    },
    {
      "text": "他們從上個星期到這個星期都在討論計畫。",
      "pinyin": "Tāmen cóng shàng ge xīngqī dào zhè ge xīngqī dōu zài tǎolùn jìhuà.",
      "pinyin_numeric": "ta1men5 cong2 shang4 ge5 xing1qi1 dao4 zhe4 ge5 xing1qi1 dou1 zai4 tao3lun4 ji4hua4.",
      "translation_en": "They have been discussing the plan from last week to this week.",
      "translation_ko": "그들은 지난주부터 이번 주까지 계획을 논의하고 있어요."
    }
  ]
}
